fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let mode = required_bool(params, "mode").map_err(anyhow::Error::msg)?;
    let mungemode = required_bool(params, "mungemode").map_err(anyhow::Error::msg)?;
    let munge = required_f32(params, "munge").map_err(anyhow::Error::msg)?;
    let lfocycle = required_f32(params, "lfocycle").map_err(anyhow::Error::msg)?;
    let lfodepth = required_f32(params, "lfodepth").map_err(anyhow::Error::msg)?;
    let delay1 = required_f32(params, "delay1").map_err(anyhow::Error::msg)?;
    let fb1 = required_f32(params, "fb1").map_err(anyhow::Error::msg)?;
    let pan1 = required_f32(params, "pan1").map_err(anyhow::Error::msg)?;
    let vol1 = required_f32(params, "vol1").map_err(anyhow::Error::msg)?;
    let delay2 = required_f32(params, "delay2").map_err(anyhow::Error::msg)?;
    let fb2 = required_f32(params, "fb2").map_err(anyhow::Error::msg)?;
    let pan2 = required_f32(params, "pan2").map_err(anyhow::Error::msg)?;
    let vol2 = required_f32(params, "vol2").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_MODE, if mode { 1.0 } else { 0.0 }),
        (PORT_CTRL_MUNGEMODE, if mungemode { 1.0 } else { 0.0 }),
        (PORT_CTRL_MUNGE, munge),
        (PORT_CTRL_LF_OCYCLE, lfocycle),
        (PORT_CTRL_LF_ODEPTH, lfodepth),
        (PORT_CTRL_DELAY1, delay1),
        (PORT_CTRL_FB1, fb1),
        (PORT_CTRL_PAN1, pan1),
        (PORT_CTRL_VOL1, vol1),
        (PORT_CTRL_DELAY2, delay2),
        (PORT_CTRL_FB2, fb2),
        (PORT_CTRL_PAN2, pan2),
        (PORT_CTRL_VOL2, vol2),
    ];

    let extra_outs: &[usize] = &[PORT_AUDIO_OUT_OUT_R];
    let _ = layout;
    let processor = lv2::build_lv2_processor_with_extras(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT_L], control_ports, extra_outs)?;
    Ok(BlockProcessor::Mono(Box::new(processor)))
}

